Method.Source:
/// <summary>
///  Main method to initialize the constructor of the class
/// </summary>
/// <param name = "_args">Report args</param>
public static void main(Args _args)
{
    KJP_SM_BSetInvoiceController::construct(_args).startOperation();
}

    /// <summary>
    ///  Constructor method for the class
    /// </summary>
    /// <param name = "_args">Report args</param>
    /// <returns>construct for class</returns>
    public static KJP_SM_BSetInvoiceController construct(Args _args)
    {
        KJP_SM_BSetInvoiceController  controller = new KJP_SM_BSetInvoiceController();

        controller.parmReportName(ssrsReportStr(KJP_SM_BSetInvoiceReport, Report));
        controller.parmArgs(_args);
        controller.parmLoadFromSysLastValue(false);
        controller.parmShowDialog(false);

        return controller;
    }

    /// <summary>
    /// set pdf file name when download from preview
    /// </summary>
    protected void runToScreen()
    {
        Filename  fileName;
        System.DateTime outputDateTime = DateTimeUtil::applyTimeZoneOffset(DateTimeUtil::getSystemDateTime(), Timezone::GMTPLUS0900OSAKA_SAPPORO_TOKYO);
        str dateStr = KJP_CM_Utils::convertDate2StryyyyMMdd(dateTimeUtil::date(outputDateTime), DateSeparator::None);
        str timeStr = subStr(outputDateTime.ToString('yyyyMMddHHmmss'),9,14);

        fileName = SysLabel::labelId2String(literalStr("@KJP:KJP103402")) + KJP_CM_ConstantHelper::underscore + dateStr + KJP_CM_ConstantHelper::underscore + timeStr;

        this.parmDialogCaption(fileName);

        super();
    }

    /// <summary>
    /// modify the contract before the dialog is shown to the user
    /// </summary>
    protected void prePromptModifyContract()
    {
        KJP_SM_BSetInvoiceContract  contract;
        KJP_SM_BSetInvoiceView      selectedRecords;
        List recIdList = new List(Types::Int64);

        MultiSelectionHelper selectionHelper = MultiSelectionHelper::construct();
        selectionHelper.parmDatasource(args.record().dataSource());
        selectedRecords = selectionHelper.getFirst();

        while (selectedRecords)
        {
            recIdList.addEnd(selectedRecords.CustInvoiceJourRecId);
            selectedRecords = selectionHelper.getNext();
        }
        
        contract = this.parmReportContract().parmRdpContract() as KJP_SM_BSetInvoiceContract;
        contract.parmRecId(recIdList);

        super();
    }
